// MARK: - KeychainService

class KeychainService {
    static let shared = KeychainService()
    private let serviceIdentifier = "com.yourcompany.CryptoWallet.privateKey"

    private init() {}

    func savePrivateKey(_ keyData: Data, tag: String) -> OSStatus {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceIdentifier,
            kSecAttrAccount as String: tag,
            kSecValueData as String: keyData,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly // Strongest reasonable accessibility for MVP
        ]

        SecItemDelete(query as CFDictionary) // Delete existing item before adding
        return SecItemAdd(query as CFDictionary, nil)
    }

    func loadPrivateKey(tag: String) -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceIdentifier,
            kSecAttrAccount as String: tag,
            kSecReturnData as String: kCFBooleanTrue!,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]

        var item: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &item)

        guard status == errSecSuccess else {
            print("Keychain load error: \(status)")
            return nil
        }

        return item as? Data
    }

    func deletePrivateKey(tag: String) -> OSStatus {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceIdentifier,
            kSecAttrAccount as String: tag
        ]
        return SecItemDelete(query as CFDictionary)
    }
}

// MARK: - WalletManager

enum WalletError: Error, LocalizedError {
    case keyGenerationFailed
    case keyNotFound
    case signingFailed
    case invalidPrivateKeyData
    case keychainError(OSStatus)

    var errorDescription: String? {
        switch self {
        case .keyGenerationFailed: return "Failed to generate a new private key."
        case .keyNotFound: return "No private key found in the wallet."
        case .signingFailed: return "Failed to sign the transaction."
        case .invalidPrivateKeyData: return "Invalid private key data loaded from storage."
        case .keychainError(let status): return "Keychain operation failed with status: \(status)."
        }
    }
}

class WalletManager: ObservableObject {
    @Published var privateKey: P256.Signing.PrivateKey?
    @Published var publicKey: P256.Signing.PublicKey?
    @Published var walletAddress: String?
    @Published var lastError: WalletError?

    private let keyTag = "myWalletPrivateKey"

    init() {
        loadKey()
    }

    func generateNewKey() {
        do {
            let newPrivateKey = P256.Signing.PrivateKey()
            let keyData = newPrivateKey.rawRepresentation
            let status = KeychainService.shared.savePrivateKey(keyData, tag: keyTag)

            guard status == errSecSuccess else {
                throw WalletError.keychainError(status)
            }

            self.privateKey = newPrivateKey
            self.publicKey = newPrivateKey.publicKey
            self.walletAddress = deriveAddress(from: newPrivateKey.publicKey)
            self.lastError = nil
        } catch {
            self.privateKey = nil
            self.publicKey = nil
            self.walletAddress = nil
            self.lastError = error as? WalletError ?? .keyGenerationFailed
            print("Error generating key: \(error.localizedDescription)")
        }
    }

    func loadKey() {
        guard let keyData = KeychainService.shared.loadPrivateKey(tag: keyTag) else {
            self.privateKey = nil
            self.publicKey = nil
            self.walletAddress = nil
            self.lastError = .keyNotFound
            return
        }

        do {
            let loadedPrivateKey = try P256.Signing.PrivateKey(rawRepresentation: keyData)
            self.privateKey = loadedPrivateKey
            self.publicKey = loadedPrivateKey.publicKey
            self.walletAddress = deriveAddress(from: loadedPrivateKey.publicKey)
            self.lastError = nil
        } catch {
            self.privateKey = nil
            self.publicKey = nil
            self.walletAddress = nil
            self.lastError = .invalidPrivateKeyData
            print("Error loading key: \(error.localizedDescription)")
        }
    }

    func signTransaction(message: Data) -> Data? {
        guard let privateKey = privateKey else {
            self.lastError = .keyNotFound
            return nil
        }

        do {
            let signature = try privateKey.signature(for: message)
            self.lastError = nil
            return signature.rawRepresentation
        } catch {
            self.lastError = .signingFailed
            print("Error signing transaction: \(error.localizedDescription)")
            return nil
        }
    }

    func deleteKey() {
        let status = KeychainService.shared.deletePrivateKey(tag: keyTag)
        if status == errSecSuccess {
            self.privateKey = nil
            self.publicKey = nil
            self.walletAddress = nil
            self.lastError = nil
        } else {
            self.lastError = .keychainError(status)
        }
    }

    private func deriveAddress(from publicKey: P256.Signing.PublicKey) -> String {
        // For MVP, a simple hex representation of the public key or its hash.
        // In a real app, this would be specific to the blockchain (e.g., Ethereum checksum address, Bitcoin base58).
        let publicKeyData = publicKey.rawRepresentation
        let hashed = SHA256.hash(data: publicKeyData)
        return hashed.compactMap { String(format: "%02x", $0) }.joined().prefix(40).uppercased() // Simplified for display
    }
}

