// MARK: - ContentView

struct ContentView: View {
    @StateObject private var walletManager = WalletManager()
    @State private var transactionMessage: String = "Hello Blockchain!"
    @State private var signedTransactionData: Data?
    @State private var blockchainServiceMessage: String?
    @State private var showingAlert = false
    @State private var alertMessage: String = ""

    private let blockchainService = BlockchainService()

    var body: some View {
        NavigationView {
            Form {
                Section("Wallet Status") {
                    if let address = walletManager.walletAddress {
                        Text("Wallet Address:")
                        Text(address)
                            .font(.footnote)
                            .textSelection(.enabled)
                    } else {
                        Text("No wallet loaded.")
                    }
                    if let publicKey = walletManager.publicKey {
                        Text("Public Key:")
                        Text(publicKey.rawRepresentation.base64EncodedString())
                            .font(.footnote)
                            .lineLimit(1)
                            .textSelection(.enabled)
                    }
                }

                Section("Wallet Actions") {
                    Button("Generate New Key") {
                        walletManager.generateNewKey()
                        if let error = walletManager.lastError {
                            alertMessage = error.localizedDescription
                            showingAlert = true
                        } else {
                            alertMessage = "New key generated and saved!"
                            showingAlert = true
                        }
                        signedTransactionData = nil
                        blockchainServiceMessage = nil
                    }
                    .disabled(walletManager.privateKey != nil)

                    Button("Load Key from Keychain") {
                        walletManager.loadKey()
                        if let error = walletManager.lastError {
                            alertMessage = error.localizedDescription
                            showingAlert = true
                        } else {
                            alertMessage = "Key loaded successfully!"
                            showingAlert = true
                        }
                        signedTransactionData = nil
                        blockchainServiceMessage = nil
                    }
                    .disabled(walletManager.privateKey != nil)

                    Button("Delete Key from Keychain") {
                        walletManager.deleteKey()
                        if let error = walletManager.lastError {
                            alertMessage = error.localizedDescription
                            showingAlert = true
                        } else {
                            alertMessage = "Key deleted!"
                            showingAlert = true
                        }
                        signedTransactionData = nil
                        blockchainServiceMessage = nil
                    }
                    .disabled(walletManager.privateKey == nil)
                    .foregroundColor(.red)
                }

                Section("Transaction") {
                    TextField("Transaction Message", text: $transactionMessage)
                        .autocapitalization(.none)
                        .disableAutocorrection(true)

                    Button("Sign Transaction") {
                        if let signedData = walletManager.signTransaction(message: transactionMessage.data(using: .utf8) ?? Data()) {
                            signedTransactionData = signedData
                            alertMessage = "Transaction signed successfully!"
                        } else {
                            alertMessage = walletManager.lastError?.localizedDescription ?? "Failed to sign transaction."
                        }
                        showingAlert = true
                        blockchainServiceMessage = nil
                    }
                    .disabled(walletManager.privateKey == nil)

                    if let signedData = signedTransactionData {
                        Text("Signed Transaction (Raw Data):")
                        Text(signedData.base64EncodedString())
                            .font(.footnote)
                            .lineLimit(2)
                            .textSelection(.enabled)

                        Button("Send Transaction to Blockchain") {
                            blockchainServiceMessage = "Sending transaction..."
                            blockchainService.sendTransaction(signedTransaction: signedData) { result in
                                switch result {
                                case .success(let message):
                                    blockchainServiceMessage = message
                                case .failure(let error):
                                    blockchainServiceMessage = "Error sending: \(error.localizedDescription)"
                                }
                            }
                        }
                    }

                    if let message = blockchainServiceMessage {
                        Text(message)
                            .font(.caption)
                            .foregroundColor(message.contains("Error") ? .red : .green)
                    }
                }
            }
            .navigationTitle("Crypto Wallet MVP")
            .alert("Wallet Status", isPresented: $showingAlert) {
                Button("OK", role: .cancel) { }
            } message: {
                Text(alertMessage)
            }
        }
    }
}

